672					#endif
673	
674					    outputs.clear();
675	
676					    eepsa.eeptpu_deinit();
677	
678					#ifdef EEP_DP_ENABLE
679					    // dp display
680					    dp_display(pic_hsize, pic_vsize, img_data_888, ARGB);
681			    	#endif
682					}
683					break;
684				default:
685					break;
686			}
687	    #ifdef EEP_DEBUG_INFO
688			if(exit_flag != 1) {
689				print("Press any key to return to main menu\r\n");
690				inbyte();
691			}
692	    #endif
693		}
694	
695	    cleanup_platform();
696	
697	    return 0;
698	}
