383	static int getArgs(int argc, char* argv[])
384	{
385	    bool b_help = false;
386	    int i = 1;
387	    while(true)
388	    {
389	        if (i >= argc) break;    
390	        const char* arg = argv[i];    
391	        
392	        if (strcmp(arg, "-h") == 0) { b_help = true; break; }
393	        else if (strcmp(arg, "--bin") == 0) 
394	        { 
395	            if (i+1 >= argc) { break; }
396	            appargs.bin_path = string(argv[++i]);
397	        }
398	        else if (strcmp(arg, "--input") == 0) 
399	        { 
400	            if (i+1 >= argc) { break; }
401	            appargs.input = string(argv[++i]);
402	        }
403	        else if (strcmp(arg, "--pixel") == 0) 
404	        { 
405	            if (i+1 >= argc) { break; }
406	            appargs.pixel_order = string(argv[++i]);
407	        }
408	        else { b_help = true; break; }
409	        i++;
410	    }
411	    if (b_help) { usage(argv[0]); return -1; }
412	    
413	    if (appargs.bin_path == "") { printf("Please set eeptpu bin path. (use -h for help)\n"); return -1; }
414	    if (appargs.input == "") { printf("Please set input. (use -h for help)\n"); return -1; }
415	    if (appargs.pixel_order != "RGB" && appargs.pixel_order != "BGR") { printf("Pixel order error, please check. (use -h for help)\n"); return -1; }
416	    
417	    return 0;
418	}
