169	static int getArgs(int argc, char* argv[])
170	{
171	    bool b_help = false;
172	    int i = 1;
173	    while(true)
174	    {
175	        if (i >= argc) break;    
176	        const char* arg = argv[i];    
177	        
178	        if (strcmp(arg, "-h") == 0) { b_help = true; break; }
179	        else if (strcmp(arg, "--help") == 0) { b_help = true; break; }
180	        else if (strcmp(arg, "--bin") == 0) 
181	        { 
182	            if (i+1 >= argc) { break; }
183	            appargs.path_bin = string(argv[++i]);
184	        }
185	        else if (strcmp(arg, "--input") == 0) 
186	        { 
187	            if (i+1 >= argc) { break; }
188	            appargs.input = string(argv[++i]);
189	        }
190	        else if (strcmp(arg, "--iface") == 0) 
