192	            if (i+1 >= argc) { break; }
193	            int interface = atoi(argv[++i]);
194	            if (interface == 1) appargs.interface = eepInterfaceType_SOC;
195	            else if (interface == 2) appargs.interface = eepInterfaceType_PCIE;
196	        }
197	        else 
198	        {
199	            printf("Unknown: %s\n", arg);
200	            b_help = true; break; 
201	        }
202	        i++;
203	    }
204	    if (b_help) { usage(argv[0]); return -1; }
